import React from "react";

function App() {
  return (
    <div
      style={{
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        alignItems: "center",
        gap: "2rem",
        fontFamily: "Arial, sans-serif",
        backgroundColor: "#f4f4f4",
      }}
    >
      <h1
        style={{
          color: "#b80000",
          fontWeight: "bold",
          fontSize: "2.5rem",
          textAlign: "center",
          margin: 0,
        }}
      >
        ¡BALBOA ALERTA ESTÁ VIVO!
      </h1>

      <button
        style={{
          padding: "1rem 2rem",
          fontSize: "1.5rem",
          fontWeight: "bold",
          borderRadius: "12px",
          border: "none",
          backgroundColor: "#b80000",
          color: "white",
          cursor: "pointer",
        }}
        onClick={() => alert("Formulario próximamente")}
      >
        Reportar incidencia
      </button>
    </div>
  );
}

export default App;
